using SkiaSharp;

string text = "\U0001F60A";
float fontSize = 48;
string[] fontFamilies = { "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji" };

Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");
Console.WriteLine();

foreach (var fontFamily in fontFamilies)
{
    using var typeface = SKTypeface.FromFamilyName(fontFamily);
    if (typeface == null || typeface.FamilyName != fontFamily) { Console.WriteLine($"Font '{fontFamily}': NOT AVAILABLE"); continue; }
    Console.WriteLine($"Font '{fontFamily}':");
    using var font = new SKFont(typeface, fontSize);
    using var path = font.GetTextPath(text, new SKPoint(0, 0));
    Console.WriteLine($"  GetTextPath bounds: {path.Bounds}");
    Console.WriteLine($"  Path is empty: {path.IsEmpty}");
    SKRect measureBounds;
    float width = font.MeasureText(text, out measureBounds);
    Console.WriteLine($"  MeasureText width: {width}");
    Console.WriteLine($"  MeasureText bounds: {measureBounds}");
}
Console.WriteLine("SUCCESS: test completed");
